define(["core/ajax","core/notification"],function(Ajax,Notification){var envId=0;var versionId=0;function escapeAttr(s){return(s||"").replace(/&/g,"&amp;").replace(/"/g,"&quot;").replace(/'/g,"&#39;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}function escapeHtml(s){var d=document.createElement("div");d.textContent=s||"";return d.innerHTML}
function parseExisting(str){try{var a=JSON.parse(str);return Array.isArray(a)?a:[]}catch(e){return[]}}

function loadAllScenarios(body,selected,allScenarios,cb){var list=body.querySelector(".scenario-list");list.innerHTML='<div class="p-2 text-muted">Loading scenarios...</div>';Ajax.call([{methodname:"local_rangeos_list_scenarios",args:{envid:envId,search:"",classfilter:"",page:0,pagesize:999}}])[0].then(function(r){allScenarios.length=0;r.scenarios.forEach(function(sc){allScenarios.push(sc)});if(cb)cb()}).catch(Notification.exception)}

function renderList(body,selected,allScenarios,filter){var list=body.querySelector(".scenario-list");list.innerHTML="";var f=filter?filter.toLowerCase():"";var items=allScenarios;if(f){items=allScenarios.filter(function(sc){return sc.name.toLowerCase().indexOf(f)>=0})}if(!items.length){list.innerHTML='<div class="p-2 text-muted">No scenarios found.</div>';return}items.forEach(function(sc){var chk=selected.indexOf(sc.id)>=0;var row=document.createElement("label");row.className="list-group-item list-group-item-action d-flex align-items-center py-2"+(chk?" active":"");row.style.cursor="pointer";row.innerHTML='<input type="checkbox" class="mr-2" value="'+escapeAttr(sc.id)+'" '+(chk?"checked":"")+"> <div><strong>"+escapeHtml(sc.name)+"</strong></div>";var cb=row.querySelector("input");cb.addEventListener("change",function(){if(cb.checked){if(selected.indexOf(sc.id)<0)selected.push(sc.id);row.classList.add("active")}else{var idx=selected.indexOf(sc.id);if(idx>=0)selected.splice(idx,1);row.classList.remove("active")}updateBadges(body,selected,allScenarios)});list.appendChild(row)})}

function updateBadges(body,selected,allScenarios){var el=body.querySelector(".scenario-selected-badges");if(!selected.length){el.innerHTML='<span class="text-muted">None selected</span>';return}var h="";selected.forEach(function(id){var name=id;for(var i=0;i<allScenarios.length;i++){if(allScenarios[i].id===id){name=allScenarios[i].name;break}}h+='<span class="badge badge-primary mr-1 mb-1">'+escapeHtml(name)+' <a href="#" class="text-white ml-1 scenario-rm" data-id="'+escapeAttr(id)+'">&times;</a></span>'});el.innerHTML=h;el.querySelectorAll(".scenario-rm").forEach(function(a){a.addEventListener("click",function(e){e.preventDefault();var rid=a.dataset.id;var idx=selected.indexOf(rid);if(idx>=0)selected.splice(idx,1);updateBadges(body,selected,allScenarios);var c=body.querySelector('.scenario-list input[value="'+rid+'"]');if(c){c.checked=false;c.closest("label").classList.remove("active")}})})}

function patchAuConfig(auId,classMode,defaultClassId){if(!versionId)return;Ajax.call([{methodname:"local_rangeos_patch_au_config",args:{versionid:versionId,auid:auId,classmode:classMode,defaultclassid:defaultClassId}}])[0].then(function(){Notification.addNotification({message:"Class mode updated.",type:"success"})}).catch(Notification.exception)}

function showCreateClassForm(scenarioUuid,auTitle){var mid="cm"+Date.now();var jq=window.jQuery||window.$;var w=document.createElement("div");w.innerHTML='<div class="modal fade" id="'+mid+'" tabindex="-1" role="dialog"><div class="modal-dialog" role="document"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Create class</h5><button type="button" class="close" data-dismiss="modal"><span>&times;</span></button></div><div class="modal-body"><p class="text-muted mb-3">Create a class for: <strong>'+escapeHtml(auTitle)+'</strong></p><div class="form-group"><label for="'+mid+'-classid">Class ID</label><input type="text" class="form-control" id="'+mid+'-classid" placeholder="e.g. cyber-101-spring-2026"><small class="form-text text-muted">A unique identifier for this class batch.</small></div><div class="form-group"><label for="'+mid+'-count">Number of seats</label><input type="number" class="form-control" id="'+mid+'-count" value="10" min="1" max="500"><small class="form-text text-muted">Number of scenario instances to pre-deploy.</small></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-dismiss="modal">Cancel</button><button type="button" class="btn btn-success" id="'+mid+'-create">Create</button></div></div></div></div>';document.body.appendChild(w);var mel=document.getElementById(mid);jq(mel).modal("show");document.getElementById(mid+"-create").addEventListener("click",function(){var classId=document.getElementById(mid+"-classid").value.trim();var count=parseInt(document.getElementById(mid+"-count").value,10);if(!classId){Notification.addNotification({message:"Class ID is required.",type:"error"});return}if(!count||count<1){Notification.addNotification({message:"Count must be at least 1.",type:"error"});return}var btn=document.getElementById(mid+"-create");btn.disabled=true;btn.textContent="Creating...";Ajax.call([{methodname:"local_rangeos_create_class",args:{envid:envId,scenarioid:scenarioUuid,classid:classId,count:count}}])[0].then(function(){jq(mel).modal("hide");Notification.addNotification({message:'Class "'+classId+'" created with '+count+" seats.",type:"success"})}).catch(function(err){btn.disabled=false;btn.textContent="Create";Notification.exception(err)})});jq(mel).on("hidden.bs.modal",function(){w.remove()})}

function createDefaultMapping(auId,auTitle,defaultName){var btn=document.querySelector('[data-action="create-default-mapping"][data-auid="'+CSS.escape(auId)+'"]');var orig=btn?btn.innerHTML:"";if(btn){btn.disabled=true;btn.textContent="Searching..."}Ajax.call([{methodname:"local_rangeos_list_scenarios",args:{envid:envId,search:defaultName,classfilter:"",page:0,pagesize:100}}])[0].then(function(r){var sc=(r.scenarios||[]).find(function(s){return s.name===defaultName});if(sc){showForm(auId,auTitle,JSON.stringify([sc.id]),false,defaultName)}else{Notification.addNotification({message:'Default scenario "'+defaultName+'" was not found in this environment.',type:"warning"})}}).catch(Notification.exception).finally(function(){if(btn){btn.disabled=false;btn.innerHTML=orig}})}

function showForm(auId,auTitle,existingSc,isEdit,defaultName){var t=isEdit?"Edit mapping":"Create mapping";var mid="mm"+Date.now();var selected=parseExisting(existingSc);var allSc=[];var defaultHint=defaultName?'<div class="alert alert-info py-2 mb-2"><small>Default scenario from course config: <strong>'+escapeHtml(defaultName)+'</strong></small></div>':"";var w=document.createElement("div");w.innerHTML='<div class="modal fade" id="'+mid+'" tabindex="-1" role="dialog"><div class="modal-dialog modal-lg" role="document"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">'+escapeHtml(t)+'</h5><button type="button" class="close" data-dismiss="modal"><span>&times;</span></button></div><div class="modal-body"><div class="form-group"><label>AU IRI</label><input type="text" class="form-control" id="'+mid+'-auid" value="'+escapeAttr(auId)+'" '+(auId?"readonly":"")+'></div><div class="form-group"><label>Mapping Name</label><input type="text" class="form-control" id="'+mid+'-name" value="'+escapeAttr(auTitle)+'"></div><hr>'+defaultHint+'<h6>Scenarios</h6><div class="scenario-selected-badges mb-2"><span class="text-muted">None selected</span></div><div class="mb-2"><input type="text" class="form-control scenario-search" placeholder="Type to filter scenarios..."></div><div class="scenario-list list-group" style="max-height:300px;overflow-y:auto"></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" id="'+mid+'-cancel">Cancel</button><button type="button" class="btn btn-primary" id="'+mid+'-save">Save</button></div></div></div></div>';document.body.appendChild(w);var mel=document.getElementById(mid);var body=mel.querySelector(".modal-body");var si=body.querySelector(".scenario-search");

loadAllScenarios(body,selected,allSc,function(){renderList(body,selected,allSc,"");updateBadges(body,selected,allSc)});

si.addEventListener("input",function(){renderList(body,selected,allSc,si.value.trim())});

var jq=window.jQuery||window.$;jq(mel).modal("show");
document.getElementById(mid+"-cancel").addEventListener("click",function(){jq(mel).modal("hide")});
document.getElementById(mid+"-save").addEventListener("click",function(){var a=document.getElementById(mid+"-auid").value.trim();var n=document.getElementById(mid+"-name").value.trim();if(!a){Notification.addNotification({message:"AU IRI is required.",type:"error"});return}var call;if(selected.length===0&&isEdit){call={methodname:"local_rangeos_delete_au_mapping",args:{envid:envId,auid:a}}}else if(isEdit){call={methodname:"local_rangeos_update_au_mapping",args:{envid:envId,auid:a,name:n,scenarios_json:JSON.stringify(selected)}}}else{if(selected.length===0){Notification.addNotification({message:"Select at least one scenario.",type:"error"});return}call={methodname:"local_rangeos_create_au_mapping",args:{envid:envId,auid:a,name:n,scenarios_json:JSON.stringify(selected)}}}Ajax.call([call])[0].then(function(){jq(mel).modal("hide");window.location.reload()}).catch(Notification.exception)});jq(mel).on("hidden.bs.modal",function(){w.remove()})}

return{init:function(){var es=document.getElementById("rangeos-env-select");if(es){envId=parseInt(es.value,10);es.addEventListener("change",function(e){envId=parseInt(e.target.value,10);var el=document.querySelector("[data-baseurl]");if(el){var u=el.dataset.baseurl;window.location.href=u+(u.indexOf("?")>=0?"&":"?")+"envid="+envId}})}var vc=document.querySelector("[data-versionid]");if(vc){versionId=parseInt(vc.dataset.versionid,10)||0}document.addEventListener("change",function(e){var toggle=e.target.closest('[data-action="toggle-classmode"]');if(toggle){patchAuConfig(toggle.dataset.auid,toggle.checked,"")}});document.addEventListener("focusout",function(e){var input=e.target.closest('[data-action="defaultclassid-input"]');if(input){var auId=input.dataset.auid;var toggle=document.querySelector('[data-action="toggle-classmode"][data-auid="'+auId+'"]');var cm=toggle?toggle.checked:false;patchAuConfig(auId,cm,input.value.trim())}});document.addEventListener("click",function(e){var b=e.target.closest('[data-action="create-mapping"]');if(b){e.preventDefault();showForm(b.dataset.auid||"",b.dataset.autitle||"",b.dataset.scenarios||"[]",false);return}b=e.target.closest('[data-action="edit-mapping"]');if(b){e.preventDefault();showForm(b.dataset.auid||"",b.dataset.autitle||"",b.dataset.scenarios||"[]",true);return}b=e.target.closest('[data-action="create-default-mapping"]');if(b){e.preventDefault();createDefaultMapping(b.dataset.auid||"",b.dataset.autitle||"",b.dataset.defaultscenarioname||"");return}b=e.target.closest('[data-action="create-class"]');if(b){e.preventDefault();showCreateClassForm(b.dataset.scenariouuid||"",b.dataset.autitle||"")}})}};});
